INSERT INTO public.photos VALUES (23824, 'Elefantes en el Ayuntamiento 1966', 'Desfile circense de elefantes ante el edificio del Ayuntamiento de Zaragoza en la plaza del Pilar, un aâ”śâ–’o despuâ”śÂ®s de su inauguraciâ”śâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1072998256062443&set=...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20089378261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20089378261.webp', 'https://www.flickr.com/photos/zaragozaantigua/20089378261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23829, 'Calle del Pilar aâ”śâ–’os 30', 'Calle del Pilar. En el centro, verja del palacio de los marqueses de Ayerbe. A la derecha, la Lonja. Fuente: www.facebook.com/photo.php?fbid=10203611134318762&set...', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65584700, -0.87717800, '0101000020E61000007AA9D898D711ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21105527093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21105527093.webp', 'https://www.flickr.com/photos/zaragozaantigua/21105527093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23836, 'Plaza del Pilar 1955', '"Plaza del Pilar. Ayuntamiento. Basâ”śÂˇlica de Nuestra Seâ”śâ–’ora del Pilar. Jardines. Farolas". El ciclo vital de los efemerâ”śâ”‚pteros, en su fase de insecto volador, es de menos de un dâ”śÂˇa de duraciâ”śâ”‚n. Para ellos, "toda la vida imaginable" es un largo lapso de apenas 24 horas. Una peculiar caracterâ”śÂˇstica de los indâ”śÂˇgenas de esta ciudad preserva esta distintiva distorsiâ”śâ”‚n temporal desde los antiguos tiempos de nuestra etapa evolutiva como insectos, y la condensa en la popular y sâ”śâ”‚lidamente arraigada expresiâ”śâ”‚n "esto es asâ”śÂˇ de toda la vida". En la imagen, son los mediados de los aâ”śâ–’os 50 del pasado siglo. Nos separan de ella apenas sesenta de los mâ”śĂ­s de 2000 aâ”śâ–’os de "historia" de esta ciudad, y nos encontramos con que la "tradicional" plaza del Pilar sigue en construcciâ”śâ”‚n. A la izquierda, el nuevo edificio del Gobierno Civil ha sido terminado ha poco. A la derecha, la nueva Casa Consistorial continâ”śâ•‘a en obras. A la recientâ”śÂˇsima nueva fachada del Pilar aâ”śâ•‘n le faltan 14 aâ”śâ–’os para contener la escultura-retablo de Pablo Serrano de la virgen encolumnada, y las torres de la cara ribereâ”śâ–’a del templo, prosiguen su laboriosa trama. Al fondo, el monumento "A los hâ”śÂ®roes y mâ”śĂ­rtires de Zaragoza. Caâ”śÂˇdos en la Cruzada de Liberaciâ”śâ”‚n 1936-1939", ha sido inaugurado hace poco, y el solar donde se proyecta levantar los "Juzgados y Magistratura de Trabajo de Zaragoza", seguirâ”śĂ­ asâ”śÂˇ unos aâ”śâ–’os aâ”śâ•‘n. Por no existir, no existe ni la "tradicional" ofrenda de flores: faltan tres aâ”śâ–’os para que sea "inventada", como local reformulaciâ”śâ”‚n de lo que ya venâ”śÂˇa haciâ”śÂ®ndose en otros sitios. "O tempora, o mores". Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22892412665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22892412665.webp', 'https://www.flickr.com/photos/zaragozaantigua/22892412665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23846, 'Vuelta ciclista 1965', 'El corredor Josâ”śÂ® Martâ”śÂˇn Colmenarejo ganâ”śâ”‚ la 13â”¬Â¬ etapa (Lâ”śÂ®rida-Zaragoza) de la Vuelta ciclista a Espaâ”śâ–’a 1965. En la imagen, llegada del mâ”śÂˇtico Federico Martâ”śÂˇn Bahamontes, entonces en el equipo "Inuri - Margnat", en su â”śâ•‘ltimo aâ”śâ–’o como corredor profesional. Terminâ”śâ”‚ esta carrera en la posiciâ”śâ”‚n 10 de la clasificaciâ”śâ”‚n general. Al fondo, la torre de la Seo. Fuente: Agencia EFE.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65588700, -0.87781100, '0101000020E6100000B53522180717ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24533529201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24533529201.webp', 'https://www.flickr.com/photos/zaragozaantigua/24533529201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23852, 'Plaza del Pilar 1987', 'Imagen de la plaza del Pilar capturada desde la replaceta del Gobierno Civil. En primer plano, el "templete" de la Oficina Municipal de Turismo, que pretendâ”śÂˇa rememorar al postmoderno gusto de la "movida", el original templo romano cuyos restos quedaron destruidos al construirse los garajes subterrâ”śĂ­neos que estâ”śĂ­n justo debajo. Luego vendrâ”śÂˇan las recreaciones 3-D de la Zaragoza romana, y otras inimaginables aplicaciones en el momento de la imagen. Fuente visual: www.flickr.com/photos/30957604@N06/12235618614/in/photoli...', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65564100, -0.87818600, '0101000020E610000005C3B986191AECBF5875560BECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27098587790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27098587790.webp', 'https://www.flickr.com/photos/zaragozaantigua/27098587790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23854, 'Plaza del Pilar 1955', 'Las obras del nuevo ayuntamiento progresaban a un ritmo tranquilo, y ya casi habâ”śÂˇa transcurrido una dâ”śÂ®cada desde que en 1946 se pusiera oficialmente la primera piedra. A la izquierda, los caâ”śâ–’izos del andamiaje indican que el trabajo continâ”śâ•‘a en la parte mâ”śĂ­s prâ”śâ”‚xima al paseo de Echegaray y Caballero. Mientras tanto, su fachada principal aparece casi terminada, si bien todavâ”śÂˇa sin los iconos protectores de la ciudad que aâ”śâ–’os despuâ”śÂ®s flanquearâ”śÂˇan la puerta de acceso. Mientras tanto, la Casa Consistorial continuaba funcionalmente radicada en la plaza de Santo Domingo. Sobre la despejada y gran plaza de las Catedrales se destacan algunos elementos decorativos para dar siquiera algo de color y vida a tanto metro cuadrado de dura superficie. Al fondo, la plaza de La Seo y su isleta de verdor. Esta captura fue realizada por el fotâ”śâ”‚grafo francâ”śÂ®s Jean Paul Margnac en el verano de 1955, durante su paso por la penâ”śÂˇnsula Ibâ”śÂ®rica, desde Parâ”śÂˇs, y con destino hacia tierras mâ”śĂ­s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/11012390964/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27208679602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27208679602.webp', 'https://www.flickr.com/photos/zaragozaantigua/27208679602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23861, 'Plaza del Pilar 1967', 'Imagen capturada durante la encabalgada lectura del pregâ”śâ”‚n de las fiestas mayores de Zaragoza, a cargo de su "pregonero mayor", Ignacio Moreno Bregante, disfrazado a la carpetovetâ”śâ”‚nica usanza de esa Edad Media pasada por el vestuario ye-ye de la venganza de don Mendo, y a juego con el resto de figurantes municipales. Autoridades y nutrido pâ”śâ•‘blico a la escucha, en una escenificaciâ”śâ”‚n localizada delante del nuevo edificio consistorial. A la izquierda, el nuevo edificio del Gobierno Civil. Al fondo, el elevado y recayente tramo de la calle de Santiago, con los antiguos edificios habitacionales que lo caracterizaban. Fuente visual: Gerardo Sancho Ramo, AMZ', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65573400, -0.87796300, '0101000020E6100000362383DC4518ECBF09707A17EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29854200360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29854200360.webp', 'https://www.flickr.com/photos/zaragozaantigua/29854200360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23863, 'Pl. del Pilar 1954', 'Imagen durante el derribo de la antigua manzana de casas ubicada entre las calles de Santiago, al fondo, Bayeu, a la izquierda, Forment, a la derecha, y la desaparecida calle de Juan Martâ”śÂˇn Goicoechea, en primer plano, antigua del Horno de la Caraza. Los restos de esta fachada pertenecâ”śÂˇan, precisamente, a la casa de este Goicoechea, un destacado prâ”śâ”‚cer local (de adopciâ”śâ”‚n) de la segunda mitad del luminoso siglo XVIII. El derribo de esta antigua manzana de casas supuso la desapariciâ”śâ”‚n del â”śâ•‘ltimo tramo de esta calle-fâ”śâ”‚sil, y el derribo de la referida gran casona, con todos los elementos edilicios acompaâ”śâ–’antes. La presencia del nuevo edificio sede del Gobernador Civil, a la izquierda, justificâ”śâ”‚ entonces el derribo y allanamiento de esta manzana, cuyo solar dejâ”śâ”‚ una nueva replaceta, como acompaâ”śâ–’amiento a la necesaria gran plaza del Pilar. De rebote, un tramo de la calle de Santiago se convirtiâ”śâ”‚, sin pretenderlo, en provisional nueva fachada a esta gran plaza del Pilar. Provisional, pues hasta aquâ”śÂˇ estuvo diseâ”śâ–’ado prolongar el paseo de la Independencia, llevâ”śĂ­ndose por delante lo que hubiera, o hubiese, tal como se hizo unos aâ”śâ–’os antes con la calle de San Vicente de Paâ”śâ•‘l. Fuente visual: Josâ”śÂ® Ignacio Gâ”śâ”‚mez Zorraquino, "Los Goicoechea y su interâ”śÂ®s por la tierra y el agua en el Aragâ”śâ”‚n del siglo XVIII", DGA, 1989.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65547300, -0.87811100, '0101000020E61000005B40683D7C19ECBF9C340D8AE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30147416835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30147416835.webp', 'https://www.flickr.com/photos/zaragozaantigua/30147416835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23882, 'Pl. del Pilar 1954', 'Imagen capturada durante el derribo de la antigua manzana de casas ubicada entre las calles de Santiago, Bayeu, Forment, y la de Juan Martâ”śÂˇn Goicoechea. Los restos de la fachada pertenecâ”śÂˇan a la casona familiar de Juan Goicoechea, destacado prâ”śâ”‚cer local (de adopciâ”śâ”‚n) durante la segunda mitad del luminoso siglo XVIII. El derribo estaba justificado para dar espacio al nuevo edificio, a la izquierda, del Gobierno Civil, y porque este era el tramo final del prolongado paseo de la Independencia, que hasta aquâ”śÂˇ deberâ”śÂˇa haber llegado, en lâ”śÂˇnea recta desde la plaza de Espaâ”śâ–’a. Cuando este delirio no fue acometido, quedâ”śâ”‚ una linda replaceta dura. En la imagen, visita oficial de inspecciâ”śâ”‚n de obra. Entre los notables, el alcalde Luis Gâ”śâ”‚mez Laguna, y el jefe del Movimiento Nacional y Gobernador Civil de Zaragoza, Josâ”śÂ® Manuel Pardo de Santayana. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65547300, -0.87811100, '0101000020E61000005B40683D7C19ECBF9C340D8AE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31533505165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31533505165.webp', 'https://www.flickr.com/photos/zaragozaantigua/31533505165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23907, 'Plaza del Pilar c.1942', 'Despejada imagen capturada en la nueva plaza del Pilar resultante del derribo de las manzanas de viviendas del oriente de la antigua plaza, entre las calles del Pilar y de Goicoechea, y entre las de Damiâ”śĂ­n Forment y Don Jaime I. A la derecha, inmuebles del lado de los impares de la antigua calle del Pilar entre la Lonja y el homâ”śâ”‚nimo templo, que poco despuâ”śÂ®s serâ”śÂˇan derribados para dejar paso a la nueva Casa Consistorial.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65569500, -0.87761800, '0101000020E610000090300C587215ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51410527146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51410527146.webp', 'https://www.flickr.com/photos/zaragozaantigua/51410527146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23912, 'Plaza del Pilar c.1968', 'Imagen capturada en la plaza del Pilar con un turâ”śÂˇstico posado ante el monumento a Goya inaugurado en 1960 en la zona inmediata a la Lonja. Justo tras ellos destaca el cenotafio de Goya que hasta esa fecha habâ”śÂˇa estado ubicado en el Rincâ”śâ”‚n de Goya del parque del General Primo de Rivera. Como impresionante telâ”śâ”‚n de fondo, la barroca torre de La Seo del Salvador en su Epifanâ”śÂˇa que se alza desde la plaza homâ”śâ”‚nima, donde a la izquierda, a la altura del Cine Pax, aparece estacionado un tranvâ”śÂˇa articulado de la serie 250 en servicio en la lâ”śÂˇnea 10 "Academia", lâ”śÂˇnea que serâ”śÂˇa clausurada en enero de 1971, y este tranvâ”śÂˇa desguazado poco despuâ”śÂ®s. Durante las obras de reforma de la plaza en 1990 este entorno fue modificado sustancialmente.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65560700, -0.87710300, '0101000020E6100000D026874F3A11ECBFAC0320EEEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53274149940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53274149940.webp', 'https://www.flickr.com/photos/zaragozaantigua/53274149940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24080, 'Calle de Espoz y Mina 1937', 'Imagen capturada desde el inmueble del nâ”¬â•‘ 51-55 de la calle de Espoz y Mina y centrada en los destrozos ocasionados en el inmueble del nâ”¬â•‘ 44-46 de esa misma calle, con el que confrontaba. El dâ”śÂˇa 3 de mayo de 1937, a las 18:30 h, una bomba de aviaciâ”śâ”‚n de la Fuerzas Aâ”śÂ®reas de la Repâ”śâ•‘blica Espaâ”śâ–’ola impactâ”śâ”‚ directamente en â”śÂ®l. Otra bomba cayâ”śâ”‚ en las inmediaciones. El resultado fue espantoso: un centenar de heridos y muertos. Esta casa conservaba hasta 2021 una placa memorialista referida a este terrible suceso, incrustada en los azulejos restaurados de primer tâ”śÂ®rmino y a la derecha. Al fondo y a la izquierda sobresale la câ”śâ•‘pula del Banco Zaragozano. A la derecha, tejado y palomar del inmueble del nâ”¬â•‘ 1 de la plaza de la Constituciâ”śâ”‚n esquinero con el Coso Alto.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65426800, -0.87783300, '0101000020E6100000A92F4B3B3517ECBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38667937795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38667937795.webp', 'https://www.flickr.com/photos/zaragozaantigua/38667937795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24120, 'Plaza de Ariâ”śâ–’o 1916', 'Imagen capturada en la plaza de Ariâ”śâ–’o durante la estancia en la ciudad de una excursiâ”śâ”‚n comercial easonense, con un posado colectivo de estos donostiarras donde destacan los alcaldes de San Sebastiâ”śĂ­n (Eustaquio Inciarte Alday) y de Zaragoza (Josâ”śÂ® Salarrullana de Dios).', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65381100, -0.87817600, '0101000020E6100000213A048E041AECBFED612F14B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53502083913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53502083913.webp', 'https://www.flickr.com/photos/zaragozaantigua/53502083913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24483, 'Calle de Santiago c.1964', 'Foto: Colecciâ”śâ”‚n Jesâ”śâ•‘s Cortâ”śÂ®s Soler. Chaflâ”śĂ­n de las calles de Santiago (derecha) y Damiâ”śĂ­n Forment, sede de la Churrerâ”śÂˇa del Pilar, en el antiguo nâ”¬â•‘ 9 de la calle de Santiago. El edificio fue derribado mâ”śĂ­s tarde para completar el despeje de la recoleta zona de la plaza del Pilar frente a la fachada principal del Gobierno civil.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65540300, -0.87857300, '0101000020E610000066C1C41F451DECBFA359D93EE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23554773098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23554773098.webp', 'https://www.flickr.com/photos/zaragozaantigua/23554773098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24602, 'Plaza del Pilar 1990', 'Imagen de las obras de rehabilitaciâ”śâ”‚n y embellecimiento de la plaza del Pilar capturada durante la construcciâ”śâ”‚n del aparcamiento inmediato al Ayuntamiento y el edificio del Gobierno Civil. En el centro de la escena luce reciâ”śÂ®n restaurada la Lonja. A la derecha y al fondo, la plaza de La Seo en obras, destacando su fachada neoclâ”śĂ­sica embutida en andamios y lonas durante las tareas de limpieza y restauraciâ”śâ”‚n.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65583100, -0.87770400, '0101000020E61000003430F2B22616ECBFFB592C45F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50458743651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50458743651.webp', 'https://www.flickr.com/photos/zaragozaantigua/50458743651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24657, 'Plaza del Pilar c.1943', 'Imagen capturada en el tramo mâ”śĂ­s oriental de la ampliada plaza del Pilar, con el telâ”śâ”‚n del fondo de la plaza de La Seo. A la izquierda, vista parcial del antiguo inmueble del nâ”¬â•‘ 17 de la calle del Pilar, seguido del nâ”¬â•‘ 19 de esas misma calle que ya estâ”śĂ­ en proceso de derribo, antes de la Lonja. Sobre los solares de estos inmuebles derribados y por derribar, entre otros, estaba proyectada la construcciâ”śâ”‚n de la nueva Casa Consistorial. A la derecha, gran solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65572700, -0.87711400, '0101000020E6100000CAA31B615111ECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49213554541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49213554541.webp', 'https://www.flickr.com/photos/zaragozaantigua/49213554541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25064, 'San Valero 1965', 'Archivo Ayuntamiento de Zaragoza/Gerardo Sancho, 1965. Valero de Zaragoza fue un obispo de la ciudad que viviâ”śâ”‚ en el siglo IV. Fue maestro de San Vicente Mâ”śĂ­rtir y es el patrâ”śâ”‚n de Zaragoza. Su festividad se celebra el 29 de enero comiendo roscâ”śâ”‚n. Los zaragozanos acuden a La Seo para venerar sus reliquias y desde hace unos aâ”śâ–’os para aprovechar que es el â”śâ•‘nico dâ”śÂˇa que se accede gratis a la catedral. El dicho popular "San Valero, ventolero" alude al famoso cierzo de la ciudad, que por esas fechas se despliega con fuerza. En la foto, estatua en bronce fundido del santo, obra de Pablo Serrano, reciâ”śÂ®n colocada dos dâ”śÂˇas antes junto a la puerta del Ayuntamiento (22 de junio de 1965). En primer plano, el pedestal para situar la estatua del â”śĂĽngel de la Ciudad, que tendrâ”śĂ­ que esperar hasta el 10 de septiembre. Al fondo, el monumento a Goya y La Seo. Mâ”śĂ­s informaciâ”śâ”‚n: www.zaragoza.es/ciudad/artepublico/detalle_ArtePublico?id...', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65591000, -0.87748500, '0101000020E6100000BF60376C5B14ECBF478FDFDBF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002536010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002536010.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002536010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25139, 'Calle Espoz y Mina, 1983', 'Imagen de la medianera del Colegio Oficial de Arquitectos de Aragâ”śâ”‚n (antiguo palacio de los Torrero), pintada por Josâ”śÂ® Luis Lasala en 1977 como parte del proceso de rehabilitaciâ”śâ”‚n del edificio, cuando esta trasera era visible desde la calle Espoz y Mina, al objeto de mejorar estâ”śÂ®ticamente el entorno, esta vez sin el componente de denuncia social que se estaba dando en otras zonas degradadas de la ciudad. Aun en tiempos de notable agitaciâ”śâ”‚n socio-polâ”śÂˇtica (finales de los aâ”śâ–’os 70), cuando el patrono (aunque no pagara) era una instituciâ”śâ”‚n, el esteticismo siempre encuentra formas de prevalecer sobre otros -ismos mâ”śĂ­s radicales, por menos molesto. Es lo que tiene la abstracciâ”śâ”‚n. Lasala (componente de la agrupaciâ”śâ”‚n "Azuda 40", junto con Baquâ”śÂ®, Bayo, Cano, Fortâ”śâ•‘n...), resolviâ”śâ”‚ con una abstracciâ”śâ”‚n geomâ”śÂ®trica y colorista este mural, inmediato a un solar con la iglesia de la Santa Cruz, a la derecha, y el solar del nâ”¬â•‘ 24 de la calle Espoz y Mina (ya construido, a la izquierda). Mâ”śĂ­s tarde, los pequeâ”śâ–’os solares de los nâ”śâ•‘meros 20 y 22 serâ”śÂˇan construidos, y esta intervenciâ”śâ”‚n pictâ”śâ”‚rica, eclipsada. Fuente: Marâ”śÂˇa Luisa Grau Tello, "La pintura mural en la esfera pâ”śâ•‘blica de Zaragoza".', 1983, 1983, 1983, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65488000, -0.87795000, '0101000020E61000000EBE30992A18ECBFF9669B1BD3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22341970502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22341970502.webp', 'https://www.flickr.com/photos/zaragozaantigua/22341970502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25164, 'Palacio de los Pardo aâ”śâ–’os 30', 'Acuarela de Ambrosio Ruste. Patio de la casa Aguilar o palacio de los Pardo, en la calle de Espoz y Mina. Fuente: Lâ”śĂ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65472200, -0.87827500, '0101000020E6100000ED9E3C2CD41AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32289462012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32289462012.webp', 'https://www.flickr.com/photos/zaragozaantigua/32289462012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25649, 'Iglesia de Santiago 1874', 'Interior de la iglesia de Santiago de Zaragoza, dibujo a tinta y aguada anâ”śâ”‚nimo, 1874. "Estaba muy cerca de la catedral del Salvador (La Seo) de la que era filial. Situada en la esquina de la actual calle que conserva el nombre del templo (antes denominada Sombrererâ”śÂˇa) y los actuales nâ”śâ•‘meros 39 y 41 de la de Don Jaime I (antes Cuchillerâ”śÂˇa). En esta â”śâ•‘ltima casa se conserva un relieve recordatorio con la cruz de Santiago y la imagen del santo en el interior. Era una iglesia relativamente pequeâ”śâ–’a, con elementos decorativos româ”śĂ­nicos de gran valor. La entrada se hacâ”śÂˇa por la actual calle de Santiago, mientras que el â”śĂ­bside daba a Don Jaime . Aunque en una rehabilitaciâ”śâ”‚n posterior, se rectifica y la entrada se coloca por D. Jaime. En el â”śâ•‘ltimo cuarto del siglo XIX, por su mala conservaciâ”śâ”‚n, el templo se queda sin culto y en estado de ruina, por lo que se demuele. Previamente el patrimonio artâ”śÂˇstico que poseâ”śÂˇa se distribuye entre diversos templos de la archidiâ”śâ”‚cesis. Se conservan escasas piezas, en su mayor parte en el Museo Provincial y en el Palacio arzobispal de Zaragoza: capiteles, basas y trozos de fuste. El dibujo evidencia una imagen poco conocida de una parte de la iglesia. El templo, segâ”śâ•‘n podemos ver, se cubrâ”śÂˇa con bâ”śâ”‚veda de crucerâ”śÂˇa, parece ser que tuvo una sola nave y capillas laterales. Se puede advertir en la imagen un acceso por el lado del evangelio." En el dibujo, el acceso por la calle de Don Jaime queda a la derecha. Al fondo, los pies de la iglesia, con el coro y ventanal a la calle de Santiago. Foto: Archivo Ayuntamiento Zaragoza.', 1874, 1874, 1874, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65469900, -0.87726000, '0101000020E6100000C3D842908312ECBFA9DC442DCDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14959699729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14959699729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14959699729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25651, 'Plaza Santa Cruz aâ”śâ–’os 20', 'Preside la remozada en formas neoclâ”śĂ­sicas Casa de los Tarâ”śÂˇn, luego "del Canal Imperial". A la derecha, torre de la iglesia de Santa Cruz. La plaza es el resultado del piqueteo del antiguo palacio de los Francos de Villalba, que estaba justo enfrente de la casa de los Tarâ”śÂˇn. Fuente: Archivo Ayuntamiento de Zaragoza.', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65418300, -0.87866300, '0101000020E6100000649126DE011EECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14988320402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14988320402.webp', 'https://www.flickr.com/photos/zaragozaantigua/14988320402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25653, 'Plaza de Santa Cruz 1966', 'Plaza de Santa Cruz, con la Casa del Canal a la izquierda y la iglesia de Santa Cruz al fondo. En primer plano, la cruz referida, otro mojâ”śâ”‚n en la ciudad de la memoria histâ”śâ”‚rica, que reza la leyenda "Transeâ”śâ•‘nte, esta cruz bendita espera de ti una oraciâ”śâ”‚n por los mâ”śĂ­rtires de la guerra R.I.P." Fuente visual: Gerardo Sancho Ramo, AMZ. 24/12/1966.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211496825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211496825.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211496825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25657, 'Calle Espoz y Mina 1969', 'Imagen de la calle Espoz y Mina capturada desde el arranque de la calle Mayor, en el punto en que tal vez el decumano mâ”śĂ­ximo romano, del que estas dos calles serâ”śÂˇan herederas, se cruzase con el cardo, que vendrâ”śÂˇa a ser la calle Don Jaime I, de derecha a izquierda. En la esquina donde la seâ”śâ–’al de prohibido el paso, se alza el edificio diseâ”śâ–’ado por Francisco Albiâ”śâ–’ana, que hace estratâ”śÂ®gico chaflâ”śĂ­n. Un poco mâ”śĂ­s adelante, sobresale el alero volado del antiguo palacio renacentista de los Pardo, propiedad de la familia Moliner, y empleado como almacâ”śÂ®n de muebles. Unos pocos aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇa adquirido por una entidad local de ahorro, que lo convertirâ”śĂ­ en museo. Justo enfrente queda la iglesia de la Exaltaciâ”śâ”‚n de la Santa Cruz, pero como es tan modesta, ni se ve. A partir de ahâ”śÂˇ, la calle parece combarse hacia abajo hacia su cruce con la calle Alfonso I, y su continuaciâ”śâ”‚n natural, luego, por Manifestaciâ”śâ”‚n. Cosas de la perspectiva. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65425200, -0.87761800, '0101000020E610000090300C587215ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15676035218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15676035218.webp', 'https://www.flickr.com/photos/zaragozaantigua/15676035218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25663, 'Iglesia Santa Cruz 2006', 'Foto: Rusolera, abril de 2006. Aspecto de las traseras de la Iglesia de la Exaltaciâ”śâ”‚n de la Santa Cruz de Zaragoza (construida en 1768), con el solar resultante tras el derribo de sus construcciones anexas (restos del palacio de Osera). En 2014, tras medio siglo en ese estado, serâ”śĂ­ terminada una residencia del Opus Dei en su ubicaciâ”śâ”‚n. Fuente: zaragozaciudad.net/zaragozafluye/2014/110901-plaza-de-san...', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65445900, -0.87861700, '0101000020E61000004EB51666A11DECBF54C90050C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494849739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494849739.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494849739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25668, 'Calle Don Jaime I c.1920', 'Despejada visual de la calle de Don Jaime I, en direcciâ”śâ”‚n hacia la Lonja, que queda al fondo. A la izquierda, soleado desemboque de la calle de Espoz y Mina, con el reciente edificio chaflanero diseâ”śâ–’ado por Francisco Albiâ”śâ–’ana, de inspiraciâ”śâ”‚n moderna, y aires vieneses. Hacia la derecha, umbrâ”śÂˇo arranque de la calle Mayor hacia la Magdalena. En el suelo, el tendido viario por el que transitaban las lâ”śÂˇneas de tranvâ”śÂˇa "Arrabal" y "Gâ”śĂ­llego". Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n Simâ”śâ”‚n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65404300, -0.87779100, '0101000020E6100000EE23B726DD16ECBFC09657AEB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24810400281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24810400281.webp', 'https://www.flickr.com/photos/zaragozaantigua/24810400281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25678, 'Plaza de Santa Cruz 1922', 'Dibujo de â”śĂĽngel Dâ”śÂˇaz Domâ”śÂˇnguez que reproduce la gran fachada de la casa del siglo XVI que fue de los Tarâ”śÂˇn, del conde de Fuentes, del hospital de Gracia, del Santo Oficio y del Canal Imperial de Aragâ”śâ”‚n. Esta perspectiva es posible por el derribo de la gran casa de los Francos de Villalba, cuyo solar (en primer plano) dio origen a la plaza de Santa Cruz. A la derecha, brazo edilicio de la gran casa de los marqueses de Osera, sobre el que emerge la torrecilla de la iglesia parroquial de Santa Cruz. Fuente visual: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65439900, -0.87881900, '0101000020E6100000404F0306491FECBF7EC4AF58C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43150964012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43150964012.webp', 'https://www.flickr.com/photos/zaragozaantigua/43150964012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20886, 'Câ”śÂ®sar Augusto c.1954', 'Estatua de Câ”śÂ®sar Augusto donada por Mussolini a Zaragoza, originalmente emplazada en 1940 en la plaza de Paraâ”śÂˇso, y desde 1950 reubicada junto a la muralla de piedra inmediata al torreâ”śâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Aâ”śâ–’os despuâ”śÂ®s volverâ”śÂˇa a ser objeto de otros traslados. Fuente: AHPZ-Archivo Fotogrâ”śĂ­fico Josâ”śÂ® Galiay, (SF).', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65698400, -0.88184500, '0101000020E61000000E8464011338ECBF65FF3C0D18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700988999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700988999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700988999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20897, 'Calle Manifestaciâ”śâ”‚n 2001', 'Las obras de renovaciâ”śâ”‚n de servicios a la altura del nâ”śâ•‘mero 4 de la calle de la Manifestaciâ”śâ”‚n pusieron al descubierto un tramo significativo de losas de la calzada romana del Decumano Mâ”śĂ­ximo. Bajo â”śÂ®ste, apareciâ”śâ”‚ tambiâ”śÂ®n una cloaca romana. Al fondo, confluencia con la calle Murallas Romanas. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 2001, 2001, 2001, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23908883029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23908883029.webp', 'https://www.flickr.com/photos/zaragozaantigua/23908883029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20899, 'Torreâ”śâ”‚n muralla romana 1989', 'En el actual emplazamiento de la estatua de Augusto, junto al Mercado Central, se hallâ”śâ”‚ este basamento de un gran cubo semicircular de mâ”śĂ­s de 13 metros de diâ”śĂ­metro, de la muralla romana (siglo I). Corresponde al torreâ”śâ”‚n norte de la puerta Decumana Oeste, luego puerta de Toledo. Al fondo, iglesia de San Juan de los Panetes y solares en la calle de las Murallas Romanas. Fuera de campo y a la derecha, calle de la Manifestaciâ”śâ”‚n, antiguo Decumano Mâ”śĂ­ximo. Fuente: Zaragoza. Prehistoria y arqueologâ”śÂˇa, Ayuntamiento de Zaragoza, 1991.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24297061796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24297061796.webp', 'https://www.flickr.com/photos/zaragozaantigua/24297061796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20907, 'Antonio Pâ”śÂ®rez 1591', '"El pueblo de Zaragoza poniendo en libertad a Antonio Pâ”śÂ®rez", D. Melâ”śÂ®ndez, 1878. Xilografâ”śÂˇa. Antonio Pâ”śÂ®rez, diplomâ”śĂ­tico fugitivo de la Justicia de Felipe I, se acoge al Privilegio de Manifestaciâ”śâ”‚n en Aragâ”śâ”‚n, siendo custodiado en la Câ”śĂ­rcel Foral o de Manifestados de Zaragoza, en el torreâ”śâ”‚n sur del Arco de Toledo, en 1591. Por ello, parece que esta imagen reproduce la actual calle Manifestaciâ”śâ”‚n. Fuente: "La Academia", 23 de diciembre de 1878.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65656600, -0.88209800, '0101000020E610000088BEBB95253AECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061489001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061489001.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061489001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20915, 'Antonio Pâ”śÂ®rez 1591', '"Antonio Pâ”śÂ®rez liberado por el pueblo aragonâ”śÂ®s en 1591", â”śâ”‚leo de Manuel Ferrâ”śĂ­n, 1860. El diplomâ”śĂ­tico Antonio Pâ”śÂ®rez es liberado, en el marco de las llamadas "Alteraciones de Aragâ”śâ”‚n". Su prisiâ”śâ”‚n era la de los manifestados, en el torreâ”śâ”‚n sur del Arco de Toledo de Zaragoza.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19061099701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19061099701.webp', 'https://www.flickr.com/photos/zaragozaantigua/19061099701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20920, 'Calle Puerta de Toledo 1769', 'Plano de la calle Puerta de Toledo de Zaragoza, 1769. "Demarcaciâ”śâ”‚n de las casas que se hallan por una u otra ladera desde la casa que pretende abrir votiga Joseph Dieste, colejial cerero y confitero, Plaza del Mercado, asta la de Diego Casanoba, colejial, cerero y confitero, frente a San Antâ”śâ”‚n. Firmado por Onofre Graciâ”śĂ­n, maestro de obras." Fuente: AHPZ.', 1769, 1769, 1769, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20002419886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20002419886.webp', 'https://www.flickr.com/photos/zaragozaantigua/20002419886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21001, 'Puerta de Toledo c.1853', 'Dibujo de la antigua Puerta de Toledo (derribada finalmente en 1866) en una escena donde se muestra desde la plaza del Mercado, donde confluâ”śÂˇan las calles de la Hilarza y de los Predicadores. El edificio de la izquierda formâ”śâ”‚ parte de las antiguas carnicerâ”śÂˇas de la ciudad, y tras â”śÂ®l se ubicaba la antigua câ”śĂ­rcel o prisiâ”śâ”‚n de los Manifestados y la iglesia de San Antâ”śâ”‚n. Hacia el fondo, la calle del Arco de Toledo conducente a la subida de las Cucharas (antigua de Botoneros) y la plaza del Justicia, desde donde continuaba como calle de la Platerâ”śÂˇa. A la derecha y adosadas a la puerta, bodeguillas o tiendas comerciales. Este dibujo fue mâ”śĂ­s tarde convertido despuâ”śÂ®s en xilografâ”śÂˇa y publicado en el "Semanario Pintoresco Espaâ”śâ–’ol" (1853).', 1853, 1853, 1853, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65677700, -0.88231800, '0101000020E6100000138255F5F23BECBFEBE1CB4411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52218508522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52218508522.webp', 'https://www.flickr.com/photos/zaragozaantigua/52218508522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21002, 'Puerta de Toledo y plaza del Mercado 1867', 'A.M.Z. Sign. 0907. "La plaza del Mercado", dibujo de Enrique Laporta basado en el de Valentâ”śÂˇn Carderera de 1840, publicado en la revista El Museo Universal (17/02/1867). Esta puerta tuvo larga vida, desde la â”śÂ®poca romana (sus dos torreones corresponden a la muralla del s. IV) hasta 1848. Cerraba la ciudad hacia el este. La plaza representada estâ”śĂ­ ocupada por el actual Mercado Central, y la calle que cerraba la puerta hoy es Manifestaciâ”śâ”‚n.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65653400, -0.88215000, '0101000020E6100000265305A3923AECBF255B5D4E09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672230150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672230150.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672230150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21073, 'Plaza del Mercado 1877', '"La procesiâ”śâ”‚n de la Virgen del Pilar en Zaragoza", litografâ”śÂˇa de Mariano Teruel, 1877. Vista de la plaza del Mercado de Zaragoza, con el Torreâ”śâ”‚n de la Zuda al fondo. Fuente: "La Academia", semanario ilustrado universal, 23 de noviembre de 1877.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65635100, -0.88276900, '0101000020E610000023861DC6A43FECBF34D93F4F03D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20023326392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20023326392.webp', 'https://www.flickr.com/photos/zaragozaantigua/20023326392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21086, 'Procesiâ”śâ”‚n del Rosario 1871', '"Zaragoza. Procesiâ”śâ”‚n del Rosario en las Fiestas del Pilar". Dibujo de Francisco Pradilla publicado en el Almanaque de la Ilustraciâ”śâ”‚n para 1877, editado en 1876 por Aribau y Câ”¬Â¬, Madrid, procedente del nâ”śâ•‘mero del 30 de octubre de 1871 de la revista La Ilustraciâ”śâ”‚n, de Madrid. La procesiâ”śâ”‚n del Rosario desfila por la plaza del Mercado. Guâ”śÂˇalos numerosa clerecâ”śÂˇa y una exigua capilla musical, que entona la Letanâ”śÂˇa lauretana. Grandes farolas de extraâ”śâ–’as formas, ya representando macetas y leones, ya templetes y aun castillos, conforman el inmemorial Rosario de la imagen. En â”śÂ®l no figura aâ”śâ•‘n el gran farol del Templo del Pilar, que se situaba detrâ”śĂ­s de los leones y que se estrenâ”śâ”‚ en 1872. Es el precedente del actual Rosario de Cristal, cuyos pasos y faroles fueron diseâ”śâ–’ados por Ricardo Magdalena Tabuenca en 1889 y 1890 y realizados por el vidriero Leâ”śâ”‚n Quintana Bianchi. Fuente visual: prensahistorica.mcu.es/es/catalogo_imagenes/grupo.do?path...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65662200, -0.88260900, '0101000020E6100000ECF7C43A553EECBFC4EA8F300CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30966735445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30966735445.webp', 'https://www.flickr.com/photos/zaragozaantigua/30966735445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21151, 'Mercado de Zaragoza 1893', '"Zaragoza", acuarela de Arthur Melville, 1893. Vista interior de los porches del Mercado de Zaragoza. No confundir con el â”śâ”‚leo "The Orange Market" del mismo autor, que ha sido relacionado con la ciudad de Zaragoza y es una estampa del Puerto de Pasajes (Guipâ”śâ•‘zcoa).', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65607900, -0.88276900, '0101000020E610000023861DC6A43FECBFD34B8C65FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18456936174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18456936174.webp', 'https://www.flickr.com/photos/zaragozaantigua/18456936174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21288, 'Calle Manifestaciâ”śâ”‚n c.1908', '"Zaragoza. Plaza del Mercado." Sobresaliente imagen editada como postal en Hamburgo, por la editorial V. B. Cumbo, con una insâ”śâ”‚lito panorama del ajetreo propio del entorno del Mercado Nuevo, en su entrada norte. La imagen se ha capturado desde la calle de la Manifestaciâ”śâ”‚n. A la derecha, inmediatas, viviendas esquineras entre esa calle y la plaza de San Antonio Abad, que queda justo fuera de plano. Las traseras de estas viviendas estaban adosadas al antiguo gran complejo hospitalario de San Juan de los Panetes. Al fondo, los porches de la plaza del Mercado. y el tramo final de la calle de la Democracia, esquinero con la calle de Antonio Pâ”śÂ®rez. Mâ”śĂ­s al fondo, leve emboque al â”śÂˇnfimo callejâ”śâ”‚n del Arpa. Fuente visual: www.todocoleccion.net/', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26291005183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26291005183.webp', 'https://www.flickr.com/photos/zaragozaantigua/26291005183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21405, 'Iglesia de San Cayetano c.1915', 'Fachada de la iglesia de San Cayetano o Santa Isabel, en la plaza de San Cayetano, hoy del Justicia. Fuente: www.ebay.com/', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65595000, -0.88190000, '0101000020E6100000F1F44A598638ECBFD5E76A2BF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25477525352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25477525352.webp', 'https://www.flickr.com/photos/zaragozaantigua/25477525352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21450, 'Plaza de Lanuza c.1915', 'Imagen capturada en la plaza de Lanuza, a cierta altura y desde un inmueble de la manzana entre las calles de las Armas y de Casta â”śĂĽlvarez, con el nuevo Mercado inmediato y a la derecha, y con el fondo de la calle de Antonio Pâ”śÂ®rez, donde se destaca emergente y levemente, entre edificaciones adosadas, el Torreâ”śâ”‚n de la Zuda. En la pronunciada esquina de esta calle con el arranque de la calle de la Democracia destaca el antiguo Cafâ”śÂ® Espaâ”śâ–’ol (no confundir con el mâ”śĂ­s antiguo y homâ”śâ”‚nimo cafâ”śÂ® de la plaza de la Constituciâ”śâ”‚n). Sobre el firme, tendido tranviario de la lâ”śÂˇnea de Circunvalaciâ”śâ”‚n.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65665700, -0.88281100, '0101000020E6100000DE91B1DAFC3FECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50746748743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50746748743.webp', 'https://www.flickr.com/photos/zaragozaantigua/50746748743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21505, 'Plaza del Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Plaza del Pilar". A las 12 de la maâ”śâ–’ana de un soleado dâ”śÂˇa primaveral, los juegos de luces y sombras de la antigua plaza del Pilar festejaban los contrastes, difuminaban los espacios. La plaza lucâ”śÂˇa un microclima propio, irrepetible despuâ”śÂ®s. Era otra plaza. La imagen estâ”śĂ­ capturada desde la esquina con la calle de la Regla (que conectaba con la trasera plaza de Huesca), justo al lado del edificio que servâ”śÂˇa de vivienda y consulta al Doctor Palomar. A su izquierda, visible en la imagen, el edificio que albergâ”śâ”‚ al palacio de Aytona, y que luego serâ”śĂ­ sede de la Delegaciâ”śâ”‚n de Hacienda. Entre â”śÂ®l y el Pilar, la callecita Retiro Alto del Pilar. El ciudadano cubierto con canotier, dirigido en direcciâ”śâ”‚n hacia la calle Convertidos. Fuente visual: "Miguel y Gabriel Faci. Fotâ”śâ”‚grafos fundadores de la Real Sociedad Fotogrâ”śĂ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”śâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65684100, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15583628299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15583628299.webp', 'https://www.flickr.com/photos/zaragozaantigua/15583628299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21603, 'Plaza de Huesca 1929', '"A Zaragoza", dibujo de Fâ”śÂ®lix Gazo para la portada del Heraldo de Aragâ”śâ”‚n del 12 de octubre de 1929. Representa una escena con viajeros del coche de lâ”śÂˇnea en la plaza de Huesca, con la iglesia de San Juan de los Panetes al fondo. Fuente: www.heraldo.es', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26477374166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26477374166.webp', 'https://www.flickr.com/photos/zaragozaantigua/26477374166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21713, 'San Juan de los Panetes c.1934', 'Vista dibujada desde el Torreâ”śâ”‚n de la Zuda de la iglesia de San Juan de los panetes de Zaragoza. Fuente: Keecua.com', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65703200, -0.88167600, '0101000020E61000000B613596B036ECBF7636E49F19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18817190394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18817190394.webp', 'https://www.flickr.com/photos/zaragozaantigua/18817190394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21725, 'Pl. del Justicia 1930', 'Foto: A. de la Barrera, 1930. Imagen de la plaza del Justicia con la antigua casa de los condes de Sobradiel al fondo. Ese mismo aâ”śâ–’o serâ”śÂˇa inaugurado el edificio como Ilustre Colegio Notarial de Aragâ”śâ”‚n. Fuente: La Voz de Aragâ”śâ”‚n, 3 de abril de 1930.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65614300, -0.88195400, '0101000020E6100000BD715298F738ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357497138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357497138.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357497138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21806, 'Pl. del Justicia 1934', 'Fachada del almacâ”śÂ®n de plâ”śĂ­tanos de Pascual Castejâ”śâ”‚n, sito en la plaza del Justicia 4, esquina con la calle del Temple. Fuente: www.20minutos.es', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65592600, -0.88163200, '0101000020E6100000226DE34F5436ECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28458081882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28458081882.webp', 'https://www.flickr.com/photos/zaragozaantigua/28458081882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21861, 'Pl. de San Antâ”śâ”‚n 1933', 'Imagen capturada en la antigua y arbolada plaza de San Antonio Abad, o de San Antâ”śâ”‚n, abierto espacio resultante del derribo del que fuera convento-iglesia que la Orden Antoniana tuviera en esta ubicaciâ”śâ”‚n desde el siglo XII, y hasta su supresiâ”śâ”‚n por Bula Papal a finales del siglo XVIII. Los edificios de la imagen habâ”śÂˇan sido construidos adosados a la antigua muralla de piedra de la ciudad, y sus traseras lindaban con las de los nâ”śâ•‘meros pares de la calle de Antonio Pâ”śÂ®rez, que tambiâ”śÂ®n descansaban sobre la argamasa y piedras del recinto amurallado pâ”śÂ®treo de la ciudad. Hacia la derecha se encontraba el acceso que desde la plaza de San Antâ”śâ”‚n conducâ”śÂˇa al interior del antiguo complejo hospitalario de la Orden de San Juan de Jerusalâ”śÂ®n, al que estaban incorporados el torreâ”śâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Los edificios de la imagen mâ”śĂ­s tarde fueron derribados y la zona reordenada urbanisticamente, de forma que la plaza devino en frâ”śÂˇa calleja de limitado eco ciudadano y nula indicaciâ”śâ”‚n informativa. En no siendo asuntos referidos a mitos medievales, ni hazaâ”śâ–’as bâ”śÂ®licas, silencio, no hay banda. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36289551531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36289551531.webp', 'https://www.flickr.com/photos/zaragozaantigua/36289551531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21941, 'El Pilar aâ”śâ–’os 40', 'El Pilar, aguafuerte, Jesâ”śâ•‘s Fernâ”śĂ­ndez Barrio, Diputaciâ”śâ”‚n de Zaragoza, c. 1945-1947. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15689319950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15689319950.webp', 'https://www.flickr.com/photos/zaragozaantigua/15689319950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21966, 'Plaza del Pilar 1949', 'Imagen de la plaza del Pilar desde la leve altura del "Monumento a los Hâ”śÂ®roes y Mâ”śĂ­rtires de Nuestra Gloriosa Cruzada", en obras desde 1946. Uno de los maderos del andamiaje, a la derecha, causa un perturbador efecto â”śâ”‚ptico sobre una plaza terrosa y vacâ”śÂˇa, en construcciâ”śâ”‚n y remodelaciâ”śâ”‚n. A la izquierda, por ejemplo, donde estuviera el antiguo palacio de los Urriâ”śÂ®s y el anexo colegio de San Nicolâ”śĂ­s Tolentino, un perâ”śÂˇmetro vallado seâ”śâ–’ala el proyecto de Regino Borobio para el nuevo edificio del Colegio de Infantes, Museo Catedralicio, y viviendas para capellanes y capitulares del Pilar. Al lado, y desde 1945, estaban en pie los andamios de obra de la nueva y monumental fachada sur del Pilar, proyectada por Teodoro Râ”śÂˇos, y con 8 nuevos bultos redondos de Antonio Torres (7), y Fâ”śÂ®lix Burriel (1). Los â”śĂ­rboles del centro recuerdan el espacio de la antigua y barroca plaza del Pilar, antes de ser cortados para unificar visualmente la nueva y mayâ”śâ•‘scula plaza, concebida por el Râ”śÂ®gimen franquista como el centro espiritual e imperial de la ciudad. Fuente Visual: Fotos Ysa, Archivo Pâ”śâ•‘blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65683300, -0.87974300, '0101000020E61000005551BCCADA26ECBF7FF78E1A13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22196717455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22196717455.webp', 'https://www.flickr.com/photos/zaragozaantigua/22196717455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22013, 'Plaza del Pilar 1946', 'Familiar e inâ”śÂ®dita imagen capturada en la plaza del Pilar con el fondo de la calle de Florencio Jardiel flanqueada por el templo del Pilar a la derecha, y por el solar adjudicado a la izquierda para la construcciâ”śâ”‚n de la Casa del Cabildo, el Museo Catedralicio y el nuevo Colegio de los Infantes. Las efâ”śÂˇmeras construcciones del fondo se corresponden con los talleres y naves habilitados para el modelado y talla de las esculturas instaladas en la fachada meridional del templo durante las obras de rehabilitaciâ”śâ”‚n del templo acometidas en la segunda mitad de los aâ”śâ–’os cuarenta y primeros aâ”śâ–’os cincuenta. Estas obras fueron resultado del trabajo de escultores como Antonio Torres Clavero y Fâ”śÂ®lix Burriel, con el respaldo de Jacinto Suâ”śĂ­rez y los canteros Josâ”śÂ® Muâ”śâ–’oz, Manuel Macia y Basilio Sorolla. En primer tâ”śÂ®rmino, un joven zaragozano de nombre Jaime Grima Casanova juega con su carretillo de juguete en una zona en construcciâ”śâ”‚n desde los derribos por ampliaciâ”śâ”‚n de la antigua plaza del Pilar. Le acompaâ”śâ–’a, vigilante, su abuelo.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65691400, -0.87965700, '0101000020E6100000B151D66F2626ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47671814631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47671814631.webp', 'https://www.flickr.com/photos/zaragozaantigua/47671814631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
